// Accept Splunk (alert-action, `result`-wrapped) or Elastic (ECS / Kibana alert)
// payloads and emit ONE stable internal schema. Nothing downstream ever
// touches vendor-specific field names again.
const body = $json.body ?? $json;
const raw = body.result ?? body; // Splunk alert actions wrap the event in `result`
const isEcs = !!(raw['kibana.alert.rule.name'] || raw['kibana.alert.uuid'] || raw.event?.kind);

const sevMap = { informational: 1, info: 1, low: 2, medium: 3, high: 4, critical: 5 };
const fallbackId = `gen-${Date.now()}-${Math.random().toString(16).slice(2, 10)}`;

let alert;
if (isEcs) {
  alert = {
    source: 'elastic',
    alert_id: raw['kibana.alert.uuid'] ?? raw._id ?? fallbackId,
    rule_name: raw['kibana.alert.rule.name'] ?? raw.rule?.name ?? 'unknown_rule',
    severity: String(raw['kibana.alert.severity'] ?? raw.event?.severity_label ?? 'medium').toLowerCase(),
    timestamp: raw['@timestamp'] ?? new Date().toISOString(),
    entity: {
      host: raw.host?.name ?? null,
      user: raw.user?.name ?? null,
      src_ip: raw.source?.ip ?? null,
      dest_ip: raw.destination?.ip ?? null,
      process: raw.process?.command_line ?? null,
    },
    description: raw['kibana.alert.reason'] ?? raw.message ?? '',
  };
} else {
  alert = {
    source: 'splunk',
    alert_id: raw.event_id ?? body.sid ?? fallbackId,
    rule_name: body.search_name ?? raw.search_name ?? 'unknown_rule',
    severity: String(raw.severity ?? raw.urgency ?? 'medium').toLowerCase(),
    timestamp: raw._time ?? new Date().toISOString(),
    entity: {
      host: raw.dest_host ?? raw.host ?? null,
      user: raw.user ?? null,
      src_ip: raw.src_ip ?? raw.src ?? null,
      dest_ip: raw.dest_ip ?? raw.dest ?? null,
      process: raw.process ?? null,
    },
    description: raw.signature ?? raw.message ?? '',
  };
}

alert.severity_num = sevMap[alert.severity] ?? 3;
alert.raw = raw;

// Input validation: fallback defaults must not turn an empty/garbage POST
// into a billable LLM call — require at least one identifying field.
alert.invalid = !raw.event_id && !body.sid && !raw['kibana.alert.uuid'] && !body.search_name && !raw.signature && !raw['kibana.alert.rule.name'] && !raw.message;

// Deterministic dedup key when the source sent no id: random fallback ids
// would never dedup a redelivered payload — hash the content instead.
if (String(alert.alert_id).startsWith('gen-')) {
  const basis = JSON.stringify([alert.rule_name, alert.entity, alert.timestamp]);
  let h = 0;
  for (let i = 0; i < basis.length; i++) { h = ((h << 5) - h + basis.charCodeAt(i)) | 0; }
  alert.alert_id = 'h-' + (h >>> 0).toString(16);
}

// Minimal sanitized view for the LLM: no raw passthrough, per-field length
// caps, delimiter escape so data can't break out of the <alert> block.
const esc = v => String(v ?? '').replaceAll('</alert>', '[/alert]').slice(0, 500);
alert.prompt_payload = JSON.stringify({
  alert_id: alert.alert_id,
  source: alert.source,
  rule_name: esc(alert.rule_name),
  severity: alert.severity,
  timestamp: alert.timestamp,
  entity: Object.fromEntries(Object.entries(alert.entity).map(([k, v]) => [k, v === null ? null : esc(v)])),
  description: esc(alert.description),
}, null, 2);

// Webhook senders retry on timeout — dedup on alert_id so a redelivered
// event never produces a second Slack card (bounded to last 500 ids).
const sd = $getWorkflowStaticData('global');
const seen = sd.seen_alert_ids ?? [];
alert.duplicate = seen.includes(alert.alert_id);
if (!alert.duplicate) {
  seen.push(alert.alert_id);
  if (seen.length > 500) seen.splice(0, seen.length - 500);
}
sd.seen_alert_ids = seen;

return [{ json: alert }];

// Defensive parse: LLM output is advisory and may be malformed.
// Anything that fails validation routes to 'needs_review' — never default-allow.
const alert = $('Normalize Alert').item.json;
let out = $json.message?.content ?? $json.output ?? $json.text ?? $json;
if (typeof out === 'string') {
  const m = out.match(/\{[\s\S]*\}/);
  try { out = m ? JSON.parse(m[0]) : null; } catch (e) { out = null; }
}
const allowed = ['true_positive', 'false_positive', 'benign_true_positive'];
const valid = out && typeof out === 'object' && allowed.includes(out.verdict);

// Strip Slack-active characters from LLM prose so a prompt-injected model
// can't smuggle channel mentions or links into the alert card.
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 600);

return {
  json: {
    ...alert,
    verdict: valid ? out.verdict : 'needs_review',
    confidence: valid ? Math.min(100, Math.max(0, Number(out.confidence) || 0)) : 0,
    rationale: valid ? clean(out.rationale) : 'LLM output failed schema validation (or the LLM call itself failed) — routed to analyst review.',
    mitre_techniques: valid && Array.isArray(out.mitre_techniques) ? out.mitre_techniques.map(t => ({ id: clean(t?.id).slice(0, 12), name: clean(t?.name) })) : [],
    recommended_actions: valid && Array.isArray(out.recommended_actions) ? out.recommended_actions.map(clean) : [],
  },
};

