// Structured audit record for every side-effect: what was decided, what was
// sent where, and when. Bounded to the last 300 records in staticData —
// production would insert into an audit table instead (see README).
const sd = $getWorkflowStaticData('global');
const log = sd.audit_log ?? [];
log.push({
  ts: new Date().toISOString(),
  workflow: '01-alert-triage-llm',
  alert_id: $json.alert_id ?? null,
  rule_name: $json.rule_name ?? null,
  verdict: $json.verdict ?? null,
  confidence: $json.confidence ?? null,
  delivery_ok: !$json.error,
  delivery_error: $json.error ? String($json.error.message ?? $json.error).slice(0, 200) : null,
  notified: $json.error ? null : ($json.verdict === 'needs_review' ? '#soc-escalations' : '#soc-alerts'),
});
if (log.length > 300) log.splice(0, log.length - 300);
sd.audit_log = log;
return { json: $json };
